import React from 'react'
import {RowPlaceCard} from './RowPlaceCard'
import {ResourceIcon} from '../../icons/ResourceIcon'

const imgStyle = {
  backgroundColor: 'white',
  maxWidth: '100%',
  objectFit: 'contain',
  pointerEvents: 'none',
  maxHeight: 48,
}

const image = <img
  src={'data:image/png;base64,'}
  style={imgStyle}
/>

const imageLarge = <img
  src="data:image/png;base64,"
  style={{
    ...imgStyle,
    maxHeight: 150,
  }}
/>

export default {
  title: 'Canvas/RowPlaceCard',
  argTypes: {
    size: {
      options: ['small', 'large'],
      control: {type: 'select'},
    },
    isPlaced: {
      control: 'boolean',
    },
    canPlace: {
      control: 'boolean',
    },
  },
}

const Template = (args) => {
  const isLarge = args.size === 'large'
  return (
    <div style={{height: isLarge ? 150 : 48}}>
      <RowPlaceCard {...args} getIcon={() => isLarge ? imageLarge : image} />
    </div>
  )
}

const TemplateIcon = (args) => {
  const isLarge = args.size === 'large'
  return (
    <div style={{height: isLarge ? 150 : 48}}>
      <RowPlaceCard {...args} getIcon={() => <ResourceIcon icon="fridge" tenant="hopara" size={isLarge ? 75 : undefined}/>} />
    </div>
  )
}

export const Image = Template.bind({})
Image.args = {
  canPlace: false,
  isPlaced: false,
  size: 'small',
}

export const Icon = TemplateIcon.bind({})
Icon.args = {
  canPlace: false,
  isPlaced: false,
  size: 'small',
}
